146	func (r SyncRequest) Validate() error {
147		return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
148	}
149	
150	func (r PlanRequest) Validate() error {
151		return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
152	}
