191	func bridgeEndpoint(ep Endpoint) internalbridge.Endpoint {
192		return internalbridge.Endpoint{
193			URL:                    ep.URL,
194			FollowInfoRefsRedirect: ep.FollowInfoRefsRedirect,
195		}
196	}
197	
198	func bridgeEndpointAuth(auth EndpointAuth) internalbridge.EndpointAuth {
199		return internalbridge.EndpointAuth{
200			Username:      auth.Username,
201			Token:         auth.Token,
202			BearerToken:   auth.BearerToken,
203			SkipTLSVerify: auth.SkipTLSVerify,
204		}
205	}
206	
207	func bridgeScope(scope RefScope) internalbridge.RefScope {
208		mappings := make([]internalbridge.RefMapping, 0, len(scope.Mappings))
209		for _, mapping := range scope.Mappings {
210			mappings = append(mappings, internalbridge.RefMapping{
211				Source: mapping.Source,
212				Target: mapping.Target,
213			})
214		}
215		return internalbridge.RefScope{
216			Branches:           append([]string(nil), scope.Branches...),
217			Mappings:           mappings,
218			AllRefs:            scope.AllRefs,
219			ExcludeRefPrefixes: append([]string(nil), scope.ExcludeRefPrefixes...),
220		}
221	}
222	
223	func bridgePolicy(policy SyncPolicy) internalbridge.SyncPolicy {
224		return internalbridge.SyncPolicy{
225			Mode:           internalbridge.OperationMode(policy.Mode),
226			IncludeTags:    policy.IncludeTags,
227			ForceWithLease: policy.ForceWithLease,
228			ForceBlind:     policy.ForceBlind,
229			Prune:          policy.Prune,
230			BestEffort:     policy.BestEffort,
231			Protocol:       internalbridge.ProtocolMode(policy.Protocol),
232		}
233	}
234	
235	func validateOperationMode(mode OperationMode) error {
236		switch mode {
237		case "", ModeSync, ModeReplicate:
238			return nil
239		default:
240			return fmt.Errorf("unsupported operation mode %q", mode)
241		}
242	}
243	
244	func ptr[T any](v T) *T {
245		return &v
246	}
247	
248	func validationMappings(mappings []RefMapping) []validation.RefMapping {
249		out := make([]validation.RefMapping, 0, len(mappings))
250		for _, mapping := range mappings {
251			out = append(out, validation.RefMapping{
252				Source: mapping.Source,
253				Target: mapping.Target,
254			})
255		}
256		return out
257	}
