package gitsync

import (
	"github.com/go-git/go-git/v6/plumbing"

	"entire.io/entire/git-sync/internal/planner"
	"entire.io/entire/git-sync/internal/syncer"
)

// RefKind classifies a ref in results.
type RefKind string

const (
	RefKindBranch = RefKind(planner.RefKindBranch)
	RefKindTag    = RefKind(planner.RefKindTag)
	RefKindOther  = RefKind(planner.RefKindOther)
)

// Action is the planned or executed per-ref action.
type Action string

const (
	ActionCreate = Action(planner.ActionCreate)
	ActionUpdate = Action(planner.ActionUpdate)
	ActionDelete = Action(planner.ActionDelete)
	ActionSkip   = Action(planner.ActionSkip)
	ActionBlock  = Action(planner.ActionBlock)
	ActionWarn   = Action(planner.ActionWarn)
)

// RefResult describes the outcome for a single ref.
type RefResult struct {
	Branch     string  `json:"branch"`
	SourceRef  string  `json:"sourceRef"`
	TargetRef  string  `json:"targetRef"`
	SourceHash string  `json:"sourceHash"`
	TargetHash string  `json:"targetHash"`
	Kind       RefKind `json:"kind"`
	Action     Action  `json:"action"`
	Reason     string  `json:"reason"`
}

// RefPlan is a planned ref action; it has the same shape as RefResult.
type RefPlan = RefResult

// RefInfo is a ref name and its hash as reported by a probe.
type RefInfo struct {
	Name string `json:"name"`
	Hash string `json:"hash"`
}

// ServiceStats aggregates request counters for one git service.
type ServiceStats struct {
	Name          string `json:"name"`
	Requests      int    `json:"requests"`
	RequestBytes  int64  `json:"requestBytes"`
	ResponseBytes int64  `json:"responseBytes"`
	Wants         int    `json:"wants"`
	Haves         int    `json:"haves"`
	Commands      int    `json:"commands"`
}

// SideBytes reports transfer volume and timing for one side of a sync.
type SideBytes struct {
	Label       string `json:"label"`
	Bytes       int64  `json:"bytes"`
	Display     string `json:"display,omitempty"`
	ActiveNanos int64  `json:"activeNanos,omitempty"`
	IdleNanos   int64  `json:"idleNanos,omitempty"`
}

// Stats aggregates transfer statistics when CollectStats was requested.
type Stats struct {
	Enabled      bool                     `json:"enabled"`
	Items        map[string]*ServiceStats `json:"items"`
	Sides        []SideBytes              `json:"sides,omitempty"`
	ElapsedNanos int64                    `json:"elapsedNanos,omitempty"`
}

// Measurement reports process resource usage when measurement was enabled.
type Measurement struct {
	Enabled            bool   `json:"enabled"`
	ElapsedMillis      int64  `json:"elapsedMillis"`
	PeakAllocBytes     uint64 `json:"peakAllocBytes"`
	PeakHeapInuseBytes uint64 `json:"peakHeapInuseBytes"`
	TotalAllocBytes    uint64 `json:"totalAllocBytes"`
	GCCount            uint32 `json:"gcCount"`
}

// ProbeResult is the outcome of a Probe.
type ProbeResult struct {
	SourceURL     string      `json:"sourceUrl"`
	TargetURL     string      `json:"targetUrl,omitempty"`
	RequestedMode string      `json:"requestedMode"`
	Protocol      string      `json:"protocol"`
	RefPrefixes   []string    `json:"refPrefixes"`
	Capabilities  []string    `json:"sourceCapabilities"`
	TargetCaps    []string    `json:"targetCapabilities,omitempty"`
	Refs          []RefInfo   `json:"refs"`
	SourceHEAD    string      `json:"sourceHead,omitempty"`
	Stats         Stats       `json:"stats"`
	Measurement   Measurement `json:"measurement"`
}

// SyncCounts tallies per-ref outcomes of a sync.
type SyncCounts struct {
	Applied int `json:"applied"`
	Skipped int `json:"skipped"`
	Blocked int `json:"blocked"`
	Deleted int `json:"deleted"`
	Warned  int `json:"warned"`
}

// BatchSummary reports batched push progress.
type BatchSummary struct {
	Enabled bool `json:"enabled"`
	Planned int  `json:"planned"`
	Done    int  `json:"done"`
}

// ExecutionSummary describes how a sync was executed.
type ExecutionSummary struct {
	DryRun             bool         `json:"dryRun"`
	Protocol           string       `json:"protocol"`
	OperationMode      string       `json:"operationMode"`
	Relay              bool         `json:"relay"`
	TransferMode       string       `json:"transferMode"`
	Reason             string       `json:"reason"`
	BootstrapSuggested bool         `json:"bootstrapSuggested"`
	SourceHEAD         string       `json:"sourceHead,omitempty"`
	Batch              BatchSummary `json:"batch"`
}

// SyncResult is the outcome of a Sync or Replicate.
type SyncResult struct {
	Refs        []RefResult      `json:"refs"`
	Counts      SyncCounts       `json:"counts"`
	Execution   ExecutionSummary `json:"execution"`
	Stats       Stats            `json:"stats"`
	Measurement Measurement      `json:"measurement"`
}

// PlanResult is the outcome of a Plan; it has the same shape as SyncResult.
type PlanResult = SyncResult

func fromProbeResult(result syncer.ProbeResult) ProbeResult {
	out := ProbeResult{
		SourceURL:     result.SourceURL,
		TargetURL:     result.TargetURL,
		RequestedMode: result.RequestedMode,
		Protocol:      result.Protocol,
		RefPrefixes:   append([]string(nil), result.RefPrefixes...),
		Capabilities:  append([]string(nil), result.Capabilities...),
		TargetCaps:    append([]string(nil), result.TargetCaps...),
		Refs:          make([]RefInfo, 0, len(result.Refs)),
		SourceHEAD:    result.SourceHEAD.String(),
		Stats:         fromStats(result.Stats),
		Measurement:   fromMeasurement(result.Measurement),
	}
	for _, ref := range result.Refs {
		out.Refs = append(out.Refs, RefInfo{Name: ref.Name, Hash: ref.Hash.String()})
	}
	return out
}

func fromSyncResult(result syncer.Result) SyncResult {
	out := SyncResult{
		Refs: make([]RefResult, 0, len(result.Plans)),
		Counts: SyncCounts{
			Applied: result.Pushed,
			Skipped: result.Skipped,
			Blocked: result.Blocked,
			Deleted: result.Deleted,
			Warned:  result.Warned,
		},
		Execution: ExecutionSummary{
			DryRun:             result.DryRun,
			Protocol:           result.Protocol,
			OperationMode:      result.OperationMode,
			Relay:              result.Relay,
			TransferMode:       result.RelayMode,
			Reason:             result.RelayReason,
			BootstrapSuggested: result.BootstrapSuggested,
			SourceHEAD:         result.SourceHEAD.String(),
			Batch: BatchSummary{
				Enabled: result.Batching,
				Planned: result.PlannedBatchCount,
				Done:    result.BatchCount,
			},
		},
		Stats:       fromStats(result.Stats),
		Measurement: fromMeasurement(result.Measurement),
	}
	for _, plan := range result.Plans {
		out.Refs = append(out.Refs, RefResult{
			Branch:     plan.Branch,
			SourceRef:  plan.SourceRef.String(),
			TargetRef:  plan.TargetRef.String(),
			SourceHash: hashString(plan.SourceHash),
			TargetHash: hashString(plan.TargetHash),
			Kind:       RefKind(plan.Kind),
			Action:     Action(plan.Action),
			Reason:     plan.Reason,
		})
	}
	return out
}

func fromStats(stats syncer.Stats) Stats {
	out := Stats{
		Enabled:      stats.Enabled,
		Items:        make(map[string]*ServiceStats, len(stats.Items)),
		ElapsedNanos: stats.ElapsedNanos,
	}
	for key, item := range stats.Items {
		out.Items[key] = &ServiceStats{
			Name:          item.Name,
			Requests:      item.Requests,
			RequestBytes:  item.RequestBytes,
			ResponseBytes: item.ResponseBytes,
			Wants:         item.Wants,
			Haves:         item.Haves,
			Commands:      item.Commands,
		}
	}
	if len(stats.Sides) > 0 {
		out.Sides = make([]SideBytes, 0, len(stats.Sides))
		for _, side := range stats.Sides {
			out.Sides = append(out.Sides, SideBytes{
				Label:       side.Label,
				Bytes:       side.Bytes,
				Display:     side.Display,
				ActiveNanos: side.ActiveNanos,
				IdleNanos:   side.IdleNanos,
			})
		}
	}
	return out
}

func fromMeasurement(m syncer.Measurement) Measurement {
	return Measurement{
		Enabled:            m.Enabled,
		ElapsedMillis:      m.ElapsedMillis,
		PeakAllocBytes:     m.PeakAllocBytes,
		PeakHeapInuseBytes: m.PeakHeapInuseBytes,
		TotalAllocBytes:    m.TotalAllocBytes,
		GCCount:            m.GCCount,
	}
}

func hashString(hash plumbing.Hash) string {
	if hash.IsZero() {
		return ""
	}
	return hash.String()
}

package gitsync

import (
	"context"
	"errors"
	"fmt"
	"net/http"

	"entire.io/entire/git-sync/internal/syncer"
	"entire.io/entire/git-sync/internal/validation"
)

// Options configures a Client. It is intentionally small in the first public cut.
type Options struct {
	HTTPClient *http.Client
	Auth       AuthProvider
}

// Client provides the public orchestration API for git-sync.
type Client struct {
	httpClient *http.Client
	auth       AuthProvider
}

// New constructs a new Client.
func New(opts Options) *Client {
	return &Client{httpClient: opts.HTTPClient, auth: opts.Auth}
}

// Probe inspects a source remote and optional target remote.
func (c *Client) Probe(ctx context.Context, req ProbeRequest) (ProbeResult, error) {
	if err := req.Validate(); err != nil {
		return ProbeResult{}, err
	}
	cfg, err := c.buildProbeConfig(ctx, req)
	if err != nil {
		return ProbeResult{}, err
	}
	result, err := syncer.Probe(ctx, cfg)
	if err != nil {
		return ProbeResult{}, fmt.Errorf("probe: %w", err)
	}
	return fromProbeResult(result), nil
}

// Plan computes ref actions without pushing.
func (c *Client) Plan(ctx context.Context, req PlanRequest) (PlanResult, error) {
	if err := req.Validate(); err != nil {
		return PlanResult{}, err
	}
	cfg, err := c.buildSyncConfig(ctx, SyncRequest(req), true)
	if err != nil {
		return PlanResult{}, err
	}
	result, err := syncer.Run(ctx, cfg)
	if err != nil {
		return PlanResult{}, fmt.Errorf("plan: %w", err)
	}
	return fromSyncResult(result), nil
}

// Sync executes a sync between two remotes.
func (c *Client) Sync(ctx context.Context, req SyncRequest) (SyncResult, error) {
	if err := req.Validate(); err != nil {
		return SyncResult{}, err
	}
	cfg, err := c.buildSyncConfig(ctx, req, false)
	if err != nil {
		return SyncResult{}, err
	}
	result, err := syncer.Run(ctx, cfg)
	if err != nil {
		return SyncResult{}, fmt.Errorf("sync: %w", err)
	}
	return fromSyncResult(result), nil
}

// Replicate executes source-authoritative relay-only replication between two remotes.
func (c *Client) Replicate(ctx context.Context, req SyncRequest) (SyncResult, error) {
	req.Policy.Mode = ModeReplicate
	return c.Sync(ctx, req)
}

func (c *Client) buildProbeConfig(ctx context.Context, req ProbeRequest) (syncer.Config, error) {
	sourceAuth, err := c.authFor(ctx, req.Source, SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	cfg := syncer.Config{
		Source:             syncerEndpoint(req.Source, sourceAuth),
		HTTPClient:         c.httpClient,
		IncludeTags:        req.IncludeTags,
		AllRefs:            req.AllRefs,
		ExcludeRefPrefixes: append([]string(nil), req.ExcludeRefPrefixes...),
		ShowStats:          req.CollectStats,
		ProtocolMode:       protocolString(req.Protocol),
	}
	if req.Target != nil {
		targetAuth, err := c.authFor(ctx, *req.Target, TargetRole)
		if err != nil {
			return syncer.Config{}, err
		}
		cfg.Target = syncerEndpoint(*req.Target, targetAuth)
	}
	return cfg, nil
}

func (c *Client) buildSyncConfig(ctx context.Context, req SyncRequest, dryRun bool) (syncer.Config, error) {
	sourceAuth, err := c.authFor(ctx, req.Source, SourceRole)
	if err != nil {
		return syncer.Config{}, err
	}
	targetAuth, err := c.authFor(ctx, req.Target, TargetRole)
	if err != nil {
		return syncer.Config{}, err
	}
	return syncer.Config{
		Source:                 syncerEndpoint(req.Source, sourceAuth),
		Target:                 syncerEndpoint(req.Target, targetAuth),
		HTTPClient:             c.httpClient,
		Branches:               append([]string(nil), req.Scope.Branches...),
		Mappings:               validationMappings(req.Scope.Mappings),
		AllRefs:                req.Scope.AllRefs,
		ExcludeRefPrefixes:     append([]string(nil), req.Scope.ExcludeRefPrefixes...),
		IncludeTags:            req.Policy.IncludeTags,
		DryRun:                 dryRun,
		ShowStats:              req.CollectStats,
		Mode:                   operationModeString(req.Policy.Mode),
		ForceWithLease:         req.Policy.ForceWithLease,
		ForceBlind:             req.Policy.ForceBlind,
		Prune:                  req.Policy.Prune,
		BestEffort:             req.Policy.BestEffort,
		ProtocolMode:           protocolString(req.Policy.Protocol),
		MaterializedMaxObjects: syncer.DefaultMaterializedMaxObjects,
	}, nil
}

func (c *Client) authFor(ctx context.Context, endpoint Endpoint, role EndpointRole) (EndpointAuth, error) {
	if c.auth == nil {
		return EndpointAuth{}, nil
	}
	auth, err := c.auth.AuthFor(ctx, endpoint, role)
	if err != nil {
		return EndpointAuth{}, fmt.Errorf("resolve auth for %s: %w", role, err)
	}
	return auth, nil
}

func (r SyncRequest) Validate() error {
	return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
}

func (r PlanRequest) Validate() error {
	return validateSyncFields(r.Source, r.Target, r.Scope, r.Policy)
}

// validateSyncFields validates the fields shared by SyncRequest and
// PlanRequest, whose Validate methods are otherwise identical.
func validateSyncFields(source, target Endpoint, scope RefScope, policy SyncPolicy) error {
	if source.URL == "" {
		return errors.New("source URL is required")
	}
	if target.URL == "" {
		return errors.New("target URL is required")
	}
	if err := validateOperationMode(policy.Mode); err != nil {
		return err
	}
	if err := policy.Validate(); err != nil {
		return err
	}
	if _, err := validation.NormalizeProtocolMode(string(policy.Protocol)); err != nil {
		return fmt.Errorf("normalize protocol: %w", err)
	}
	if _, err := validation.ValidateMappings(validationMappings(scope.Mappings), scope.AllRefs); err != nil {
		return fmt.Errorf("validate mappings: %w", err)
	}
	return nil
}

func (r ProbeRequest) Validate() error {
	if r.Source.URL == "" {
		return errors.New("source URL is required")
	}
	if r.Target != nil && r.Target.URL == "" {
		return errors.New("target URL is required when target endpoint is provided")
	}
	if _, err := validation.NormalizeProtocolMode(string(r.Protocol)); err != nil {
		return fmt.Errorf("normalize protocol: %w", err)
	}
	return nil
}

func syncerEndpoint(ep Endpoint, auth EndpointAuth) syncer.Endpoint {
	return syncer.Endpoint{
		URL:                    ep.URL,
		Username:               auth.Username,
		Token:                  auth.Token,
		BearerToken:            auth.BearerToken,
		SkipTLSVerify:          auth.SkipTLSVerify,
		FollowInfoRefsRedirect: ep.FollowInfoRefsRedirect,
	}
}

func protocolString(mode ProtocolMode) string {
	if mode == "" {
		return string(ProtocolAuto)
	}
	return string(mode)
}

func operationModeString(mode OperationMode) string {
	if mode == "" {
		return string(ModeSync)
	}
	return string(mode)
}

func validateOperationMode(mode OperationMode) error {
	switch mode {
	case "", ModeSync, ModeReplicate:
		return nil
	default:
		return fmt.Errorf("unsupported operation mode %q", mode)
	}
}

func validationMappings(mappings []RefMapping) []validation.RefMapping {
	out := make([]validation.RefMapping, 0, len(mappings))
	for _, mapping := range mappings {
		out = append(out, validation.RefMapping{
			Source: mapping.Source,
			Target: mapping.Target,
		})
	}
	return out
}

